class Solution:
    def getIntersectionNode(self, headA, headB):
        def length(node):
            n = 0
            while node:
                n += 1
                node = node.next
            return n
        la, lb = length(headA), length(headB)
        a, b = headA, headB
        while la > lb:
            a = a.next
            la -= 1
        while lb > la:
            b = b.next
            lb -= 1
        while a is not b:
            a = a.next
            b = b.next
        return a

